content.css:
.evm-visual-host {
  display: block;
  overflow: hidden;
  font-family: "Segoe UI", Arial, sans-serif;
  color: #00145C;
}
.evm-dashboard {
  position: relative;
  display: grid;
  grid-template-columns: minmax(58px, 64px) minmax(0, 1fr);
  gap: 8px;
  overflow: hidden;
  background: #F7F9FC;
  box-sizing: border-box;
  padding: 6px;
  height: 100%;
  min-height: 0;
}
.evm-card {
  background: #FFFFFF;
  border: 1px solid #DDE3F0;
  border-radius: 8px;
  box-shadow: 0 1px 6px rgba(0, 27, 142, 0.08);
}
.evm-sidebar {
  position: relative;
  z-index: 50;
  display: flex;
  flex-direction: column;
  min-width: 0;
  padding: 6px 5px;
  background: #FFFFFF;
  border: 1px solid #DDE3F0;
  border-radius: 8px;
  pointer-events: auto;
}
.evm-logo {
  display: none;
}
.evm-menu,
.evm-menu-footer {
  position: relative;
  z-index: 50;
  display: grid;
  gap: 6px;
  pointer-events: auto;
}
.evm-menu-footer {
  margin-top: auto;
}
.evm-menu-item {
  position: relative;
  z-index: 1;
  border: 0;
  background: transparent;
  font-family: inherit;
  cursor: pointer;
  pointer-events: auto;
  display: grid;
  grid-template-columns: 1fr;
  align-items: center;
  justify-items: center;
  min-height: 34px;
  padding: 7px 4px;
  border-radius: 6px;
  color: #001B8E;
  font-size: 11px;
  font-weight: 700;
}
.evm-menu-item.disabled,
.evm-menu-item:disabled {
  cursor: default;
  opacity: 0.38;
}
.evm-menu-item span:not(.evm-menu-icon) {
  display: none;
}
.evm-menu-item.active,
.evm-menu-item.sidebar-item--active {
  color: #FFFFFF;
  background: #001B8E;
}
.evm-menu-item.ghost {
  border: 1px solid #DDE3F0;
}
.evm-menu-icon {
  font-size: 17px;
  pointer-events: none;
}
.evm-menu-group-label {
  display: none;
}
.evm-main {
  display: grid;
  grid-template-rows: 98px 349px minmax(0, 1fr);
  gap: 18px;
  min-width: 780px;
  min-height: 0;
  height: 100%;
  overflow: hidden;
}
.evm-portfolio-main {
  grid-template-rows: 96px 88px 300px minmax(0, 1fr);
  gap: 12px;
}
.evm-portfolio-header {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 150px;
  gap: 12px;
  align-items: center;
  padding: 12px 18px;
  overflow: hidden;
}
.evm-portfolio-title {
  min-width: 0;
}
.evm-breadcrumb {
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 5px;
  color: #001B8E;
  font-size: 12px;
  font-weight: 900;
}
.evm-breadcrumb button {
  border: 0;
  padding: 0;
  background: transparent;
  color: #001B8E;
  font: inherit;
  cursor: pointer;
}
.evm-breadcrumb strong {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.evm-portfolio-title h1 {
  margin: 0;
  color: #001B8E;
  font-size: 28px;
  line-height: 1.06;
  font-weight: 950;
}
.evm-portfolio-title p {
  margin: 6px 0 0;
  color: #344054;
  font-size: 13px;
  font-weight: 800;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.evm-portfolio-cutoff {
  justify-self: end;
  min-width: 130px;
  padding: 10px 12px;
  border: 1px solid #DDE3F0;
  border-radius: 7px;
  text-align: center;
  background: #F7F9FC;
}
.evm-portfolio-cutoff span,
.evm-summary-card span,
.evm-portfolio-insight > span,
.evm-insight-metric span,
.evm-entity-metric span {
  display: block;
  color: #001B8E;
  font-size: 10px;
  font-weight: 900;
  text-transform: uppercase;
}
.evm-portfolio-cutoff strong {
  display: block;
  margin-top: 3px;
  color: #00145C;
  font-size: 15px;
  font-weight: 950;
}
.evm-summary-strip {
  display: grid;
  grid-template-columns: repeat(8, minmax(0, 1fr));
  gap: 8px;
  min-width: 0;
}
.evm-summary-card {
  min-width: 0;
  padding: 10px 12px;
}
.evm-summary-card strong {
  display: block;
  margin-top: 5px;
  color: #00145C;
  font-size: 19px;
  line-height: 1.05;
  font-weight: 950;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.evm-portfolio-body {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 250px;
  gap: 12px;
  min-height: 0;
}
.evm-aggregate-curve-card,
.evm-portfolio-insight,
.evm-entity-section {
  min-width: 0;
  min-height: 0;
  padding: 12px;
  overflow: hidden;
}
.evm-aggregate-curve-svg {
  width: 100%;
  height: calc(100% - 30px);
  min-height: 230px;
  display: block;
}
.evm-aggregate-grid {
  stroke: #E4EAF5;
  stroke-width: 1.4;
}
.evm-aggregate-axis {
  stroke: #B9C4D8;
  stroke-width: 1.7;
}
.evm-aggregate-line {
  fill: none;
  stroke-width: 4;
  stroke-linecap: round;
  stroke-linejoin: round;
}
.evm-aggregate-label,
.evm-aggregate-title {
  fill: #001B8E;
  font-size: 13px;
  font-weight: 900;
}
.evm-portfolio-insight {
  display: grid;
  gap: 9px;
  align-content: start;
}
.evm-portfolio-insight > strong {
  color: #00145C;
  font-size: 24px;
  line-height: 1.05;
  font-weight: 950;
}
.evm-insight-metric {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  padding-top: 8px;
  border-top: 1px solid #E7ECF5;
}
.evm-insight-metric b {
  color: #00145C;
  font-size: 14px;
  font-weight: 950;
  text-align: right;
}
.evm-entity-section {
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  gap: 10px;
}
.evm-unit-grid {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
  min-height: 0;
  overflow: auto;
  padding-right: 2px;
}
.evm-unit-card {
  border: 1px solid #DDE3F0;
  cursor: pointer;
  text-align: left;
  padding: 12px;
  background: #FFFFFF;
}
.evm-unit-card strong {
  display: block;
  color: #001B8E;
  font-size: 17px;
  font-weight: 950;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.evm-unit-card > span {
  display: block;
  margin: 5px 0 8px;
  color: #475467;
  font-size: 12px;
  font-weight: 800;
}
.evm-entity-metric {
  display: flex;
  justify-content: space-between;
  gap: 7px;
  padding-top: 5px;
}
.evm-entity-metric b {
  color: #00145C;
  font-size: 12px;
  font-weight: 950;
}
.evm-project-list-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
  overflow: hidden;
}
.evm-project-list-table th,
.evm-project-list-table td {
  padding: 8px 9px;
  border-bottom: 1px solid #E2E8F4;
  color: #00145C;
  font-weight: 800;
  text-align: left;
  vertical-align: middle;
}
.evm-project-list-row {
  cursor: pointer;
}
.evm-project-list-row:hover td,
.evm-project-list-row:focus-visible td {
  background: #F3F6FF;
}
.evm-project-list-table th {
  color: #001B8E;
  font-size: 11px;
  font-weight: 950;
  text-transform: uppercase;
}
.evm-project-name-cell {
  max-width: 280px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.evm-row-action,
.evm-filter-clear {
  border: 0;
  border-radius: 6px;
  padding: 7px 10px;
  color: #FFFFFF;
  background: #001B8E;
  font-size: 11px;
  font-weight: 900;
  cursor: pointer;
  white-space: nowrap;
}
.evm-filter-panel {
  position: absolute;
  top: 6px;
  bottom: 6px;
  left: 78px;
  z-index: 20;
  width: 310px;
  display: grid;
  grid-template-rows: auto repeat(6, auto) minmax(0, 1fr);
  gap: 12px;
  padding: 14px;
}
.evm-filter-panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.evm-filter-panel-header strong {
  color: #001B8E;
  font-size: 18px;
  font-weight: 950;
}
.evm-filter-panel-header button {
  border: 1px solid #DDE3F0;
  border-radius: 6px;
  background: #FFFFFF;
  color: #001B8E;
  font-size: 18px;
  font-weight: 950;
  cursor: pointer;
}
.evm-filter-field {
  display: grid;
  gap: 5px;
}
.evm-filter-field span {
  color: #001B8E;
  font-size: 11px;
  font-weight: 900;
  text-transform: uppercase;
}
.evm-filter-field select {
  width: 100%;
  min-width: 0;
  padding: 8px 9px;
  border: 1px solid #C7D1E4;
  border-radius: 6px;
  color: #00145C;
  background: #FFFFFF;
  font: inherit;
  font-size: 13px;
  font-weight: 800;
}
.evm-dashboard-error {
  padding: 24px;
}
.evm-header {
  display: grid;
  grid-template-columns: minmax(0, 1fr) 520px minmax(130px, 12%);
  gap: 0;
  padding: 4px 12px;
  align-items: center;
  min-height: 0;
  overflow: hidden;
}
.evm-project-state span,
.evm-project-dates span,
.evm-performance-row span,
.evm-key-cell span {
  display: block;
  color: #001B8E;
  font-size: 10px;
  font-weight: 800;
  text-transform: uppercase;
}
.evm-project-title h1 {
  margin: 0 0 6px;
  font-size: clamp(20px, 1.35vw, 28px);
  line-height: 1.12;
  letter-spacing: 0;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.evm-project-title {
  min-width: 0;
  padding-right: 16px;
}
.evm-project-title h1 span {
  color: #001B8E;
  font-weight: 900;
  text-transform: uppercase;
}
.evm-header-meta {
  display: flex;
  flex-wrap: nowrap;
  gap: 0 18px;
  min-width: 0;
  overflow: hidden;
  color: #00145C;
  font-size: 17px;
  font-weight: 700;
  white-space: nowrap;
}
.evm-header-meta-item {
  flex: 0 1 auto;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}
.evm-header-meta b {
  color: #001B8E;
  font-weight: 950;
}
.evm-project-state {
  position: relative;
  display: grid;
  grid-template-columns: 58px minmax(0, 1fr);
  align-items: center;
  min-height: 68px;
  column-gap: 12px;
  padding: 8px 18px 8px 18px;
  border: 0;
  border-left: 1px solid #DDE3F0;
  border-radius: 0;
  overflow: hidden;
  box-shadow: none;
}
.evm-project-state.stable {
  background: transparent;
  color: #0F7A34;
}
.evm-project-state.risk {
  background: transparent;
  color: #B86500;
}
.evm-project-state.critical {
  background: transparent;
  color: #D71920;
}
.evm-project-state.critical::before {
  content: "";
  position: absolute;
  left: 0;
  top: 10px;
  bottom: 10px;
  width: 4px;
  border-radius: 999px;
  background: #D71920;
}
.evm-project-state.neutral {
  background: transparent;
  color: #001B8E;
}
.evm-project-state-icon {
  display: grid;
  place-items: center;
  width: 52px;
  height: 48px;
  border-right: 2px solid rgba(0, 27, 142, 0.12);
}
.evm-project-state.stable .evm-project-state-icon,
.evm-project-state.stable .evm-project-state-message {
  border-color: rgba(15, 122, 52, 0.2);
}
.evm-project-state.risk .evm-project-state-icon,
.evm-project-state.risk .evm-project-state-message {
  border-color: rgba(184, 101, 0, 0.22);
}
.evm-project-state.critical .evm-project-state-icon,
.evm-project-state.critical .evm-project-state-message {
  border-color: rgba(215, 25, 32, 0.2);
}
.evm-project-state.neutral .evm-project-state-icon,
.evm-project-state.neutral .evm-project-state-message {
  border-color: rgba(0, 27, 142, 0.18);
}
.evm-project-state-icon span {
  display: grid;
  place-items: center;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: #FFFFFF;
  color: currentColor;
  font-size: 28px;
  font-weight: 950;
  line-height: 1;
}
.evm-project-state.risk .evm-project-state-icon span,
.evm-project-state.critical .evm-project-state-icon span {
  clip-path: polygon(50% 8%, 94% 88%, 6% 88%);
  border-radius: 0;
  padding-top: 7px;
}
.evm-project-state.stable .evm-project-state-icon span {
  color: #0F7A34;
}
.evm-project-state.risk .evm-project-state-icon span {
  color: #B86500;
}
.evm-project-state.critical .evm-project-state-icon span {
  color: #D71920;
}
.evm-project-state-copy {
  display: flex;
  flex-direction: column;
  justify-content: center;
  min-width: 0;
  height: 100%;
  padding-left: 0;
}
.evm-project-state-body {
  display: grid;
  grid-template-columns: minmax(140px, 0.85fr) minmax(210px, 1.15fr);
  align-items: center;
  column-gap: 12px;
  min-width: 0;
  height: 100%;
  padding: 0 10px;
  border: 1px solid rgba(215, 25, 32, 0.16);
  border-radius: 8px;
  background: #FFFFFF;
}
.evm-project-state.stable .evm-project-state-body {
  border-color: rgba(15, 122, 52, 0.14);
}
.evm-project-state.risk .evm-project-state-body {
  border-color: rgba(184, 101, 0, 0.16);
}
.evm-project-state.neutral .evm-project-state-body {
  border-color: rgba(0, 27, 142, 0.14);
}
.evm-project-state .evm-project-state-copy span {
  color: #00145C;
  font-size: 14px;
  font-weight: 900;
  line-height: 1;
  text-transform: uppercase;
}
.evm-project-state strong {
  display: block;
  margin-top: 3px;
  color: currentColor;
  font-size: clamp(22px, 2.2vw, 31px);
  line-height: 1;
  text-transform: uppercase;
}
.evm-project-state-message {
  display: flex;
  align-items: center;
  justify-content: center;
  align-self: stretch;
  min-width: 0;
  height: 100%;
  padding: 0 8px;
  border-left: 0;
  color: #00145C;
  font-size: 16px;
  font-weight: 850;
  line-height: 1.12;
  text-align: center;
  overflow: hidden;
}
.evm-project-dates {
  display: flex;
  flex-direction: column;
  justify-content: center;
  min-height: 68px;
  padding: 7px 10px 7px 16px;
  text-align: center;
  border-left: 1px solid #DDE3F0;
}
.evm-project-dates span {
  font-size: 16px;
}
.evm-project-dates strong {
  display: block;
  margin: 3px 0 6px;
  font-size: 16px;
}
.evm-project-dates small {
  font-size: 15px;
  font-weight: 800;
}
.evm-gauge-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
  min-height: 0;
  height: 100%;
  overflow: hidden;
}
.evm-gauge-card {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 0;
  padding: 20px 24px;
  overflow: hidden;
  height: 100%;
  box-sizing: border-box;
  border-radius: 14px;
}
.gauge-history-card {
  position: absolute;
  left: 10px;
  right: 14px;
  bottom: 8px;
  display: grid;
  grid-template-columns: 176px 110px;
  justify-content: center;
  align-items: center;
  gap: 0;
  min-height: 54px;
  padding: 1px 0 0;
  border: 1px solid transparent;
  border-radius: 8px;
  background: linear-gradient(180deg, rgba(255, 255, 255, 0), rgba(255, 255, 255, 0));
  box-shadow: none;
  box-sizing: border-box;
  cursor: pointer;
  z-index: 2;
  transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease, background-color 180ms ease;
}
.gauge-history-card:hover,
.gauge-history-card:focus-visible {
  transform: translateY(-2px);
  border-color: rgba(219, 228, 240, 0.9);
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.92), rgba(248, 251, 255, 0.94));
  box-shadow: 0 8px 18px rgba(15, 23, 42, 0.12), 0 0 0 2px color-mix(in srgb, var(--gauge-color, #1D4DFF) 16%, transparent);
  outline: none;
}
.gauge-history-card-action {
  position: absolute;
  right: 8px;
  top: -11px;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  border: 1px solid rgba(255, 255, 255, 0.72);
  border-radius: 999px;
  background: var(--gauge-color, #1D4DFF);
  color: #FFFFFF;
  font-size: 9px;
  font-weight: 800;
  line-height: 1;
  opacity: 0;
  transform: translateY(3px);
  pointer-events: none;
  box-shadow: 0 5px 12px rgba(15, 23, 42, 0.18);
  transition: opacity 160ms ease,
        transform 160ms ease;
}
.gauge-history-card-action::before {
  content: "↗";
  color: #FFFFFF;
  font-size: 9px;
}
.gauge-history-card:hover .gauge-history-card-action,
.gauge-history-card:focus-visible .gauge-history-card-action {
  opacity: 1;
  transform: translateY(0);
}
.gauge-history-sparkline {
  justify-self: start;
  width: 188px;
  max-width: 100%;
  min-width: 0;
  height: 50px;
  transform: translateX(-12px);
}
.gauge-history-sparkline svg {
  width: 100%;
  height: 50px;
  display: block;
  overflow: visible;
}
.gauge-history-spark-area {
  fill: var(--gauge-color, #FF1E1E);
  fill-opacity: 0.04;
}
.gauge-history-spark-line {
  fill: none;
  stroke: var(--gauge-color, #FF1E1E);
  stroke-width: 4;
  stroke-linecap: round;
  stroke-linejoin: round;
  opacity: 1;
  transition: opacity 160ms ease, stroke-width 160ms ease;
}
.gauge-history-spark-point {
  fill: var(--gauge-color, #FF1E1E);
  stroke: var(--gauge-color, #FF1E1E);
  stroke-width: 0;
  vector-effect: non-scaling-stroke;
  transition: r 160ms ease, stroke-width 160ms ease;
}
.gauge-history-last-point {
  stroke-width: 0;
}
.gauge-history-card:hover .gauge-history-spark-line,
.gauge-history-card:focus-visible .gauge-history-spark-line {
  stroke-width: 4;
  opacity: 1;
}
.gauge-history-card:hover .gauge-history-spark-point,
.gauge-history-card:focus-visible .gauge-history-spark-point {
  stroke-width: 0;
}
.gauge-history-card:hover .gauge-history-last-point,
.gauge-history-card:focus-visible .gauge-history-last-point {
  r: 6.6px;
}
.gauge-history-variation {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  justify-self: end;
  width: 142px;
  padding: 0 0 1px;
  box-sizing: border-box;
  transform: translateX(64px);
}
.gauge-history-variation-value {
  display: inline-flex;
  align-items: center;
  gap: 2px;
  color: var(--gauge-color, #FF1E1E);
  font-size: 23px;
  font-weight: 900;
  line-height: 1;
  font-variant-numeric: tabular-nums;
}
.gauge-history-variation-value i {
  font-style: normal;
  font-size: 23px;
}
.gauge-history-variation-label {
  margin-top: 3px;
  padding-right: 0;
  color: #001B8E;
  font-size: 15px;
  font-weight: 900;
  line-height: 1;
  text-align: center;
  white-space: nowrap;
}
.gauge-history-card--disabled {
  display: grid;
  place-items: center;
  cursor: default;
  color: #667085;
  font-size: 11px;
  font-weight: 800;
  pointer-events: none;
}
.gauge-history-card--disabled .gauge-history-card-action {
  display: none;
}
.evm-section-title {
  margin: 0;
  color: #001B8E;
  font-size: 18px;
  font-weight: 900;
  text-transform: uppercase;
}
.evm-gauge-svg {
  width: 100%;
  max-width: 380px;
  height: calc(100% + 40px);
  max-height: none;
  display: block;
  margin: 0 auto;
  transform: translateY(18px);
}
.evm-timeline-svg text {
  fill: #001B8E;
  font-size: 11px;
  font-weight: 800;
}
.evm-curve-svg text {
  fill: #001B8E;
}
.evm-gauge-svg text {
  fill: #001B8E;
}
.evm-gauge-svg .evm-gauge-title {
  fill: #001B8E;
  font-size: 22px;
