}
.evm-body-carousel-page {
  position: absolute;
  inset: 0;
  display: grid;
  grid-template-columns: minmax(0, 70fr) minmax(360px, 30fr);
  gap: 10px;
  align-items: stretch;
  min-height: 0;
  height: 100%;
  opacity: 0;
  visibility: hidden;
  transform: translateX(18px);
  pointer-events: none;
  transition: opacity 180ms ease,
        transform 220ms ease,
        visibility 180ms ease;
}
.evm-body-carousel-page.active {
  opacity: 1;
  visibility: visible;
  transform: translateX(0);
  pointer-events: auto;
}
.evm-carousel-button {
  position: absolute;
  top: 50%;
  z-index: 6;
  width: 44px;
  height: 64px;
  display: grid;
  place-items: center;
  border: 1px solid rgba(203, 213, 225, 0.95);
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.94);
  color: #001B8E;
  cursor: pointer;
  font-size: 42px;
  font-weight: 900;
  line-height: 1;
  opacity: 0;
  pointer-events: none;
  box-shadow: 0 8px 18px rgba(15, 23, 42, 0.16);
  transform: translateY(-50%);
  transition: background-color 160ms ease, opacity 160ms ease, transform 160ms ease, box-shadow 160ms ease;
}
.evm-body-carousel:hover .evm-carousel-button,
.evm-body-carousel:focus-within .evm-carousel-button {
  opacity: 1;
  pointer-events: auto;
}
.evm-carousel-button:hover,
.evm-carousel-button:focus-visible {
  background: #FFFFFF;
  box-shadow: 0 10px 24px rgba(15, 23, 42, 0.22);
  outline: none;
  transform: translateY(-50%) scale(1.04);
}
.evm-carousel-button::after {
  content: attr(data-tooltip);
  position: absolute;
  top: 50%;
  width: max-content;
  max-width: 180px;
  padding: 7px 10px;
  border-radius: 6px;
  background: #001B8E;
  color: #FFFFFF;
  font-size: 12px;
  font-weight: 850;
  line-height: 1.15;
  opacity: 0;
  pointer-events: none;
  transform: translateY(-50%);
  transition: opacity 140ms ease;
}
.evm-carousel-button:hover::after,
.evm-carousel-button:focus-visible::after {
  opacity: 1;
}
.evm-carousel-button--prev {
  left: 12px;
}
.evm-carousel-button--prev::after {
  left: calc(100% + 10px);
}
.evm-carousel-button--next {
  right: 12px;
}
.evm-carousel-button--next::after {
  right: calc(100% + 10px);
}
