    opacity: 0;
  }
  to {
    opacity: 1;
  }
}
@keyframes gauge-modal-enter {
  from {
    opacity: 0;
    transform: translateY(18px) scale(0.97);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}
@media (max-width: 980px) {
  .evm-dashboard {
    grid-template-columns: 1fr;
  }
  .evm-sidebar {
    display: none;
  }
  .evm-main {
    min-width: 700px;
  }
  .gauge-history-modal {
    width: calc(100% - 24px);
    height: calc(100% - 24px);
    min-width: 0;
    min-height: 0;
  }
  .gauge-history-modal-body {
    grid-template-columns: 1fr;
    grid-template-rows: minmax(0, 1fr) auto;
  }
  .gauge-history-side-panel {
    grid-template-rows: auto auto auto;
  }
}
@media (max-height: 620px) {
  .gauge-history-modal-overlay {
    padding: 14px;
  }
  .gauge-history-modal-header {
    padding: 12px 16px;
  }
  .gauge-history-modal-body {
    padding: 12px 16px;
  }
  .gauge-history-modal-chart {
    min-height: 260px;
  }
  .gauge-history-info-card p,
  .gauge-history-update-card strong {
    font-size: 10px;
  }
}
